      'Date,Amount,Description,Type,Category,From Account,To Account',
      '1/5/2026,₱100.00,Test,Transfer,Transfer,Cash,Cash',
    ].join('\n');
    const result = parseCsv(csv);
    expect(result.errors).toHaveLength(1);
